const targetPosition = new Vec3(args.x, bot.entity.position.y, args.z);
const radius = args.radius;
startBackgroundSkill(bot, 'move_to_coordinate', async function (token) {
  const movements = new Movements(bot);
  bot.pathfinder.setMovements(movements);
  const goal = new goals.GoalNear(targetPosition.x, targetPosition.y, targetPosition.z, radius);
  try {
    await bot.pathfinder.goto(goal);
    if (!token.cancelled) {
      console.log('Successfully reached target coordinates: (' + targetPosition.x + ', ' + targetPosition.z + ')');
    }
  } catch (error) {
    if (token.cancelled) return;
    if (error.name === 'PathfindingNoPath') {
      console.error('No path found to (' + targetPosition.x + ', ' + targetPosition.z + ')');
    } else if (error.name !== 'Cancelled') {
      console.error('Movement failed to (' + targetPosition.x + ', ' + targetPosition.z + '):', error);
    }
  }
});
return "<MOVING>: Moving to x:" + args.x + ", z:" + args.z + " with radius " + radius + ".";
